#include <initializer_list>
#include <iostream>
#include <string>
#include <vector>

class Song
{
private:
    std::string m_title{};
    int m_duration{};
public:
    Song(const std::string& title, int duration)
        : m_title{ title }, m_duration{ duration } {}
    void print() const
    {
        std::cout << "  " << m_title << " (" << m_duration << "s)\n";
    }
};

class Playlist
{
private:
    std::vector<Song> m_songs{};
public:
    Playlist(std::initializer_list<Song> songs) : m_songs{ songs } {}
    void add(const Song& song) { m_songs.push_back(song); }
    void print() const
    {
        std::cout << "Playlist:\n";
        for (const auto& song : m_songs)
            song.print();
    }
};

int main()
{
    std::string t1{}, t2{}, t3{};
    int d1{}, d2{}, d3{};
    std::cin >> t1 >> d1 >> t2 >> d2 >> t3 >> d3;

    Playlist playlist{ Song{t1, d1}, Song{t2, d2}, Song{t3, d3} };
    playlist.print();
    std::cout << '\n';

    int n{};
    std::cin >> n;
    for (int i{ 0 }; i < n; ++i)
    {
        std::string title{};
        int duration{};
        std::cin >> title >> duration;
        playlist.add(Song{ title, duration });
    }
    playlist.print();

    return 0;
}

