#include <iostream>
#include <string>
#include <vector>

class Student
{
    std::string m_name{};
    int m_grade{};
public:
    Student(const std::string& name, int grade) : m_name{ name }, m_grade{ grade } {}
    const std::string& getName() const { return m_name; }
    int getGrade() const { return m_grade; }
};

class Classroom
{
    std::string m_name{};
    std::vector<const Student*> m_students{};
public:
    Classroom(const std::string& name) : m_name{ name } {}
    void addStudent(const Student* s) { m_students.push_back(s); }
    const std::string& getName() const { return m_name; }
    const std::vector<const Student*>& getStudents() const { return m_students; }
    int getAverageGrade() const {
        int sum{ 0 };
        for (const auto* s : m_students) sum += s->getGrade();
        return sum / static_cast<int>(m_students.size());
    }
};

void printRoster(const Classroom& room) {
    std::cout << room.getName() << " roster:\n";
    for (const auto* s : room.getStudents())
        std::cout << "  " << s->getName() << " (grade: " << s->getGrade() << ")\n";
    std::cout << "Average: " << room.getAverageGrade() << '\n';
}

int main() {
    int s{}; std::cin >> s;
    std::vector<Student> students{};
    students.reserve(s);
    for (int i{ 0 }; i < s; ++i) {
        std::string name{}; int grade{};
        std::cin >> name >> grade;
        students.emplace_back(name, grade);
    }
    int c{}; std::cin >> c;
    for (int i{ 0 }; i < c; ++i) {
        std::string roomName{}; int k{};
        std::cin >> roomName >> k;
        Classroom room{ roomName };
        for (int j{ 0 }; j < k; ++j)
        { int idx{}; std::cin >> idx; room.addStudent(&students[idx]); }
        if (i > 0) std::cout << '\n';
        printRoster(room);
    }
    return 0;
}
